            package main

import (
	"errors"
	"fmt"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs an HTML-formatted email string containing user feedback.
// The resulting string is formatted with standard MIME headers so it can be directly
// sent using the net/smtp package.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", errors.New("fromAddr and toAddr cannot be empty")
	}
	if userName == "" || subject == "" || feedbackContent == "" {
		return "", errors.New("userName, subject, and feedbackContent cannot be empty")
	}

	// Construct the email headers
	// Using a slice ensures a deterministic order for the headers
	headers := []string{
		fmt.Sprintf("From: %s", fromAddr),
		fmt.Sprintf("To: %s", toAddr),
		fmt.Sprintf("Subject: %s", subject),
		"MIME-Version: 1.0",
		"Content-Type: text/html; charset=\"UTF-8\"",
	}

	// Construct the HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body>
    <h2>User Feedback Received</h2>
    <p><strong>Username:</strong> %s</p>
    <p><strong>Subject:</strong> %s</p>
    <p><strong>Feedback Content:</strong></p>
    <div style="background-color: #f4f4f4; padding: 15px; border-radius: 5px; border-left: 4px solid #ccc;">
        %s
    </div>
</body>
</html>`, userName, subject, feedbackContent)

	// Combine headers and body. 
	// SMTP protocol requires headers and body to be separated by a blank line (\r\n\r\n).
	emailBody = strings.Join(headers, "\r\n") + "\r\n\r\n" + htmlBody

	return emailBody, nil
}

func main() {
	// Example usage
	from := "system@example.com"
	to := "support@example.com"
	userName := "johndoe"
	subject := "Bug Report: App crashes on login"
	content := "Hello Support,<br><br>When I try to log in using my credentials, the application crashes immediately. Please look into this.<br><br>Thanks!"

	emailBody, err := BuildFeedbackEmail(from, to, userName, subject, content)
	if err != nil {
		fmt.Printf("Failed to build email: %v\n", err)
		return
	}

	fmt.Println("--- Generated Email Content ---")
	fmt.Println(emailBody)
	fmt.Println("-------------------------------")

	// The generated emailBody can be directly used with net/smtp.SendMail
	// Example (commented out to avoid execution errors without an actual SMTP server):
	/*
		auth := smtp.PlainAuth("", "username", "password", "smtp.example.com")
		err = smtp.SendMail("smtp.example.com:587", auth, from, []string{to}, []byte(emailBody))
		if err != nil {
			fmt.Printf("Failed to send email: %v\n", err)
		}
	*/

	// Suppress unused import error for net/smtp in this standalone example
	_ = smtp.SendMail 
}

