// BuildFeedbackEmail generates an HTML-formatted email string containing user feedback.
// It constructs the necessary MIME headers to be sent via the net/smtp package.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the email headers required for an HTML email.
	// \r\n is the standard line ending for SMTP messages.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=\"UTF-8\"\r\n\r\n", 
		fromAddr, toAddr, subject)

	// Define the HTML template for the email body.
	// Using html/template ensures that user input is safely escaped to prevent HTML injection.
	const htmlTpl = `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif; color: #333;">
	<h2>User Feedback Received</h2>
	<p><strong>Username:</strong> {{.UserName}}</p>
	<p><strong>Subject:</strong> {{.Subject}}</p>
	<p><strong>Feedback Content:</strong></p>
	<div style="background-color: #f9f9f9; padding: 15px; border-left: 5px solid #007BFF; white-space: pre-wrap;">{{.FeedbackContent}}</div>
</body>
</html>`

	// Parse the HTML template
	t, err := template.New("feedback").Parse(htmlTpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare the data for the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute the template into a buffer
	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Combine headers and HTML body
	emailBody = headers + bodyBuffer.String()

	return emailBody, nil
}

func main() {
	// Example usage
	from := "system@example.com"
	to := "support@example.com"
	user := "JaneDoe"
