// BuildFeedbackEmail collects user feedback information and generates an HTML-formatted
// email string that can be sent using the net/smtp package.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Construct the standard MIME headers for an HTML email.
	// We use \r\n as the line ending, which is required by the SMTP protocol.
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=\"UTF-8\"\r\n\r\n", 
		fromAddr, toAddr, subject)

	// Define the HTML template for the email body.
	// Using html/template ensures that user inputs are safely escaped.
	const htmlTpl = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
    <h2>New User Feedback Received</h2>
    <hr>
    <p><strong>User Name:</strong> {{.UserName}}</p>
    <p><strong>Subject:</strong> {{.Subject}}</p>
    <p><strong>Feedback Content:</strong></p>
    <blockquote style="background-color: #f9f9f9; padding: 10px; border-left: 4px solid #ccc;">
        {{.FeedbackContent}}
    </blockquote>
</body>
</html>`

	// Parse the HTML template
	t, err := template.New("feedbackEmail").Parse(htmlTpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare the data structure for the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute the template with the provided data
	var bodyBuffer bytes.Buffer
	if err := t.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Combine the headers and the generated HTML body
	emailBody = headers + bodyBuffer.String()

	return emailBody, nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
	from := "system@example.com"
	to := "support@example.com"
	userName := "Jane Doe"
	subject := "Bug Report: Checkout Page"
	feedback := "When I try to proceed to checkout, the page freezes and I have to reload the app. Please fix this!"

	emailContent, err := BuildFeedbackEmail(from, to, userName, subject, feedback)
	if err != nil {
		fmt.Printf("Error generating email: %v\n", err)
		return
	}

	fmt.Println("--- Generated Email Content ---")
	fmt.Println(emailContent)
	fmt.Println("-------------------------------")

	// Note: To send this email using net/smtp, you would typically use:
	// err = smtp.SendMail("smtp.example.com:587", auth, from, []string{to}, []byte(emailContent))
}

