            package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate and parse email addresses format
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent email header injection by removing newlines from subject
	cleanSubject := strings.ReplaceAll(subject, "\r", "")
	cleanSubject = strings.ReplaceAll(cleanSubject, "\n", " ")

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", cleanSubject)

	// Encode subject to handle non-ASCII characters properly
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Use parsed address strings which automatically handle RFC 2047 encoding for non-ASCII names
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromParsed.String(),
		toParsed.String(),
		encodedSubject,
	)

	// Construct HTML body and escape user inputs to prevent HTML injection
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		html.EscapeString(userName),
		html.EscapeString(subject),
		html.EscapeString(feedbackContent),
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

