// BuildFeedbackEmail generates an HTML-formatted email string containing the user's feedback.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Sanitize subject to prevent email header injection (CRLF injection)
	safeSubject := strings.ReplaceAll(subject, "\r", "")
	safeSubject = strings.ReplaceAll(safeSubject, "\n", " ")

	// Construct standard email headers compatible with net/smtp
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n", fromAddr, toAddr, safeSubject)

	// Define the HTML body template
	// Using html/template ensures that user inputs are safely escaped, preventing XSS attacks.
	const htmlBody = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<title>User Feedback</title>
</head>
<body>
    <h2>New User Feedback Received</h2>
    <p><strong>User Name:</strong> {{.UserName}}</p>
    <p><strong>Subject:</strong> {{.Subject}}</p>
    <p><strong>Feedback Content:</strong></p>
    <p>{{.FeedbackContent}}</p>
</body>
</html>`

	// Parse the HTML template
	t, err := template.New("email").Parse(htmlBody)
	if err != nil {
		return "", err
	}

	// Prepare data for the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         safeSubject,
		FeedbackContent: feedbackContent,
	}

	// Buffer to store the final email content
	var buf bytes.Buffer

	// Write headers to the buffer
	buf.WriteString(headers)

	// Execute template and write the HTML body to the buffer
	err = t.Execute(&buf, data)
	if err != nil {
		return "", err
	}

	return buf.String(), nil
}

func main() {
	// Example usage
	from := "system@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Login Issue"
