// BuildFeedbackEmail constructs an HTML email string containing user feedback
// suitable for sending via net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the HTML template for the email body
	const emailTemplate = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body>
    <h2>User Feedback Received</h2>
    <p><strong>Username:</strong> {{.UserName}}</p>
    <p><strong>Subject:</strong> {{.Subject}}</p>
    <hr>
    <p><strong>Feedback Content:</strong></p>
    <p>{{.FeedbackContent}}</p>
</body>
</html>`

	// Parse the HTML template
	t, err := template.New("feedback").Parse(emailTemplate)
	if err != nil {
		return "", err
	}

	// Prepare the data for the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute the template to generate the HTML body
	var tpl bytes.Buffer
	if err := t.Execute(&tpl, data); err != nil {
		return "", err
	}

	// Construct the MIME email headers
	// The net/smtp package requires the raw message to include headers (From, To, Subject, etc.)
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=\"UTF-8\"\r\n\r\n",
		fromAddr, toAddr, subject)

	// Combine headers and HTML body
	emailBody = headers + tpl.String()

	return emailBody, nil
}

