// BuildFeedbackEmail generates an HTML-formatted email string containing user feedback.
// It constructs the MIME headers and HTML body required to send the email via net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if fromAddr == "" || toAddr == "" {
		return "", errors.New("fromAddr and toAddr cannot be empty")
	}

	// Prevent header injection vulnerabilities by removing CRLF characters from the subject
	cleanSubject := strings.ReplaceAll(subject, "\r", "")
	cleanSubject = strings.ReplaceAll(cleanSubject, "\n", "")

	// Construct the email headers. 
	// The standard requires headers and body to be separated by two CRLF (\r\n\r\n).
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=\"UTF-8\"\r\n\r\n",
		fromAddr, toAddr, cleanSubject)

	// Construct the HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
    <h2 style="color: #0056b3;">New User Feedback Received</h2>
    <table border="0" cellpadding="5" cellspacing="0">
        <tr>
            <td><strong>Username:</strong></td>
            <td>%s</td>
        </tr>
        <tr>
            <td><strong>Subject:</strong></td>
            <td>%s</td>
        </tr>
    </table>
    <hr style="border: 1px solid #eee; margin: 20px 0;">
    <h3>Feedback Content:</h3>
    <div style="background-color: #f9f9f9; padding: 15px; border-radius: 5px;">
        %s
    </div>
</body>
</html>`, userName, cleanSubject, feedbackContent)

	// Combine headers and body
	emailBody = headers + htmlBody

	return emailBody, nil
}

func main() {
	// Example configuration
	from := "system@example.com"
	to := "support@example.com"
