// BuildFeedbackEmail constructs an HTML email string containing user feedback.
// The generated string is formatted with standard MIME headers so it can be 
// directly sent using the net/smtp package.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Construct the email headers. 
	// RFC 822 requires \r\n for line breaks in headers.
	headers := ""
	headers += fmt.Sprintf("From: %s\r\n", fromAddr)
	headers += fmt.Sprintf("To: %s\r\n", toAddr)
	headers += fmt.Sprintf("Subject: %s\r\n", subject)
	headers += "MIME-Version: 1.0\r\n"
	headers += "Content-Type: text/html; charset=\"UTF-8\"\r\n"

	// Define the HTML template for the email body
	const htmlTpl = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
        .header { background-color: #f4f4f4; padding: 10px; text-align: center; }
        .content { margin-top: 20px; }
        .label { font-weight: bold; color: #555; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback Received</h2>
        </div>
        <div class="content">
            <p><span class="label">Username:</span> {{.UserName}}</p>
            <p><span class="label">Subject:</span> {{.Subject}}</p>
            <p><span class="label">Feedback Content:</span></p>
            <blockquote style="background: #f9f9f9; padding: 10px; border-left: 5px solid #ccc;">
                {{.FeedbackContent}}
            </blockquote>
        </div>
    </div>
</body>
</html>`

	// Parse the HTML template
	t, err := template.New("email").Parse(htmlTpl)
	if err != nil {
		return "", err
	}

	// Data to be injected into the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute the template into a buffer
	var body bytes.Buffer
	if err := t.Execute(&body, data); err != nil {
		return "", err
	}

	// Combine headers and body. 
	// A blank line (\r\n) separates the headers from the body.
	emailBody = headers + "\r\n" + body.String()

	return emailBody, nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function
	from := "system@example.com"
	to := "support@example.com"
	user := "gopher_dev"
	subject := "Bug report: Login page not responding"
	content := "Hi Support,\n\nWhenever I try to log in using my credentials, the loading spinner just hangs indefinitely. Please look into this.\n\nThanks!"

	emailStr, err := BuildFeedbackEmail(from, to, user, subject, content)
	if err != nil {
		fmt.Println("Error building email:", err)
		return
	}

	fmt.Println("--- Generated Email Content ---")
	fmt.Println(emailStr)
	fmt.Println("-------------------------------")

	// Note: To actually send this constructed email using the net/smtp package, 
	// you would typically do the following:
